// /frontend/src/components/Community.jsx
import React, { useEffect, useMemo, useRef, useState, useCallback } from "react";
import Composer from "./Composer";
import Post from "./Post";
import * as api from "../lib/communityApi"; // <-- new helper, see below

const USE_API = true; // flip false to use localStorage only
const LS_KEY = "wx:xstyle:v2";
const MAX_LEN = 280;

function saveLocal(posts){ try{ localStorage.setItem(LS_KEY, JSON.stringify(posts)); }catch{} }
function loadLocal(){
  try{ const raw = localStorage.getItem(LS_KEY); if(raw) return JSON.parse(raw);}catch{}
  return [];
}

export default function Community({ defaultCity = "Atlanta, GA" }) {
  const [activeTab, setActiveTab] = useState("For You"); // For You | Following | City
  const [cityFilter, setCityFilter] = useState(defaultCity);
  const [posts, setPosts] = useState(USE_API ? [] : loadLocal());
  const [hasMore, setHasMore] = useState(true);
  const [loading, setLoading] = useState(false);
  const listRef = useRef(null);
  const cursorRef = useRef(null); // for pagination cursors

  // Initial load
  useEffect(() => {
    let ignore = false;
    if (!USE_API) return;
    (async () => {
      setLoading(true);
      const { items, nextCursor } = await api.list({ city: cityFilter, tab: activeTab, limit: 20 });
      if (ignore) return;
      setPosts(items);
      cursorRef.current = nextCursor || null;
      setHasMore(!!nextCursor);
      setLoading(false);
    })();
    return () => { ignore = true; };
  // eslint-disable-next-line
  }, [cityFilter, activeTab]);

  // Save locally when not using API
  useEffect(() => { if (!USE_API) saveLocal(posts); }, [posts]);

  // Infinite scroll
  const onScroll = useCallback(async () => {
    const el = listRef.current;
    if (!el || loading || !hasMore || !USE_API) return;
    const nearBottom = el.scrollTop + el.clientHeight >= el.scrollHeight - 400;
    if (!nearBottom) return;
    setLoading(true);
    const { items, nextCursor } = await api.list({ city: cityFilter, tab: activeTab, cursor: cursorRef.current, limit: 20 });
    setPosts(p => [...p, ...items]);
    cursorRef.current = nextCursor || null;
    setHasMore(!!nextCursor);
    setLoading(false);
  }, [loading, hasMore, cityFilter, activeTab]);

  useEffect(() => {
    const el = listRef.current;
    if (!el) return;
    el.addEventListener("scroll", onScroll, { passive: true });
    return () => el.removeEventListener("scroll", onScroll);
  }, [onScroll]);

  // “Following” demo list (until backend has auth)
  const followingHandles = useMemo(() => new Set(["maya_wx", "leo_runs", "samwx", "you"]), []);

  const timeline = useMemo(() => {
    let arr = [...posts];
    if (!USE_API) {
      // local ranking/filter if no server
      if (activeTab === "Following") arr = arr.filter(p => followingHandles.has(p.author.handle));
      else if (activeTab === "City") arr = arr.filter(p => (p.city||"").toLowerCase().includes(cityFilter.toLowerCase()));
      if (activeTab === "For You")
        arr.sort((a,b)=>(b.likes+(b.reposts||0)*2)-(a.likes+(a.reposts||0)*2)||b.createdAt-a.createdAt);
      else arr.sort((a,b)=>b.createdAt-a.createdAt);
    }
    return arr;
  }, [posts, activeTab, cityFilter, followingHandles]);

  // Create
  const postNew = async ({ text, media=[], quoteOf=null, hashtags=[] }) => {
    const optimistic = {
      id: crypto.randomUUID(),
      author: { name: "You", handle: "you", avatar: "" },
      city: cityFilter,
      text, media, quoteOf,
      createdAt: Date.now(),
      likes: 0, reposts: 0, replies: [],
      youLiked: false, youReposted: false, hashtags
    };
    setPosts(p => [optimistic, ...p]);
    listRef.current?.scrollTo({ top: 0, behavior: "smooth" });
    if (!USE_API) return;

    try {
      const saved = await api.create({ text, city: cityFilter, media, quoteOf, hashtags });
      setPosts(p => p.map(x => x.id === optimistic.id ? saved : x));
    } catch {
      // rollback
      setPosts(p => p.filter(x => x.id !== optimistic.id));
    }
  };

  // Interactions
  const like = async (id) => {
    setPosts(ps => ps.map(p => p.id!==id ? p : ({ ...p, youLiked: !p.youLiked, likes: Math.max(0, p.likes + (p.youLiked?-1:1)) })));
    if (USE_API) api.like(id).catch(()=>{});
  };
  const repost = async (id) => {
    setPosts(ps => ps.map(p => p.id!==id ? p : ({ ...p, youReposted: !p.youReposted, reposts: Math.max(0, (p.reposts||0) + (p.youReposted?-1:1)) })));
    if (USE_API) api.repost(id).catch(()=>{});
  };
  const reply = async (id, text) => {
    const r = { id: crypto.randomUUID(), author:{name:"You",handle:"you",avatar:""}, text, createdAt:Date.now(), likes:0 };
    setPosts(ps => ps.map(p => p.id!==id ? p : ({ ...p, replies:[...p.replies, r] })));
    if (USE_API) {
      try {
        const saved = await api.reply(id, { text });
        setPosts(ps => ps.map(p => p.id!==id ? p : ({ ...p, replies: p.replies.map(x=>x.id===r.id? saved : x) })));
      } catch {}
    }
  };

  // Hashtag click filters timeline to City tab matching hashtag as “city” if looks like city; otherwise just sets a search.
  const onHashtagClick = (tag) => {
    // simple behavior: if tag looks like a city name token, switch to City
    setActiveTab("For You");
    // if you want: set a separate search state and filter posts by hashtag; omitted for brevity
  };

  return (
    <div className="rounded-2xl backdrop-blur-xl bg-black/40 ring-1 ring-white/10 overflow-hidden">
      {/* Header */}
      <div className="px-4 pt-3 pb-2 flex items-center justify-between gap-2">
        <div className="text-sm opacity-80">Community</div>
        <input
          value={cityFilter}
          onChange={(e) => setCityFilter(e.target.value)}
          className="bg-white/10 px-3 py-2 rounded-lg text-sm outline-none"
          placeholder="Filter by city…"
        />
      </div>

      {/* Tabs */}
      <div className="px-2 flex">
        {["For You","Following","City"].map(t=>(
          <button key={t} onClick={()=>setActiveTab(t)}
            className={`flex-1 py-2 rounded-lg text-sm ${activeTab===t?"bg-white/15":"hover:bg-white/10"}`}>
            {t}
          </button>
        ))}
      </div>

      {/* Composer (supports media + quote + hashtags) */}
      <div className="px-3 pb-2 pt-3 border-t border-white/10">
        <Composer
          maxLen={MAX_LEN}
          placeholder={`What's the weather like in ${cityFilter}?`}
          onPost={postNew}
        />
      </div>

      {/* Timeline */}
      <div ref={listRef} className="max-h-[60vh] overflow-y-auto divide-y divide-white/10">
        {timeline.map(p=>(
          <Post key={p.id} post={p}
            onLike={()=>like(p.id)}
            onRepost={()=>repost(p.id)}
            onReply={(text)=>reply(p.id,text)}
            onHashtagClick={onHashtagClick}
          />
        ))}
        {loading && <div className="py-6 text-center text-sm opacity-70">Loading…</div>}
        {!loading && !timeline.length && (
          <div className="py-10 text-center text-sm opacity-70">No posts yet. Be the first!</div>
        )}
        {!loading && hasMore && USE_API && (
          <div className="py-6 text-center text-xs opacity-60">Scroll to load more…</div>
        )}
      </div>
    </div>
  );
}
